const express = require('express');
const router = express.Router();
const TaskModel = require('../models/task');

/**
 * @route   GET /api/tasks
 * @desc    获取所有任务（支持按状态筛选）
 * @access  Public
 */
router.get('/', (req, res) => {
  try {
    const { status, limit, offset } = req.query;
    const tasks = TaskModel.findAll({
      status,
      limit: limit ? parseInt(limit) : undefined,
      offset: offset ? parseInt(offset) : undefined
    });
    res.json({
      success: true,
      data: tasks,
      meta: {
        count: tasks.length,
        timestamp: new Date().toISOString()
      }
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to fetch tasks',
      message: error.message
    });
  }
});

/**
 * @route   GET /api/tasks/:id
 * @desc    获取单个任务
 * @access  Public
 */
router.get('/:id', (req, res) => {
  try {
    const task = TaskModel.findById(req.params.id);
    if (!task) {
      return res.status(404).json({
        success: false,
        error: 'Task not found'
      });
    }
    res.json({
      success: true,
      data: task
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to fetch task',
      message: error.message
    });
  }
});

/**
 * @route   POST /api/tasks
 * @desc    创建新任务
 * @access  Public
 */
router.post('/', (req, res) => {
  try {
    const { title, description, status } = req.body;

    if (!title || typeof title !== 'string' || title.trim() === '') {
      return res.status(400).json({
        success: false,
        error: 'Title is required and must be a non-empty string'
      });
    }

    // 验证 status 字段 (如果提供)
    if (status !== undefined) {
      const validStatuses = ['pending', 'in_progress', 'completed'];
      if (!validStatuses.includes(status)) {
        return res.status(400).json({
          success: false,
          error: `Status must be one of: ${validStatuses.join(', ')}`
        });
      }
    }

    const task = TaskModel.create({
      title: title.trim(),
      description: description || '',
      status: status || 'pending'
    });

    res.status(201).json({
      success: true,
      data: task,
      message: 'Task created successfully'
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to create task',
      message: error.message
    });
  }
});

/**
 * @route   PUT /api/tasks/:id
 * @desc    更新任务
 * @access  Public
 */
router.put('/:id', (req, res) => {
  try {
    const { title, description, status } = req.body;
    const updates = {};

    if (title !== undefined) {
      if (typeof title !== 'string' || title.trim() === '') {
        return res.status(400).json({
          success: false,
          error: 'Title must be a non-empty string'
        });
      }
      updates.title = title.trim();
    }

    if (description !== undefined) {
      updates.description = description;
    }

    if (status !== undefined) {
      const validStatuses = ['pending', 'in_progress', 'completed'];
      if (!validStatuses.includes(status)) {
        return res.status(400).json({
          success: false,
          error: `Status must be one of: ${validStatuses.join(', ')}`
        });
      }
      updates.status = status;
    }

    const task = TaskModel.update(req.params.id, updates);
    if (!task) {
      return res.status(404).json({
        success: false,
        error: 'Task not found'
      });
    }

    res.json({
      success: true,
      data: task,
      message: 'Task updated successfully'
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to update task',
      message: error.message
    });
  }
});

/**
 * @route   DELETE /api/tasks/:id
 * @desc    删除任务
 * @access  Public
 */
router.delete('/:id', (req, res) => {
  try {
    const deleted = TaskModel.delete(req.params.id);
    if (!deleted) {
      return res.status(404).json({
        success: false,
        error: 'Task not found'
      });
    }
    res.json({
      success: true,
      message: 'Task deleted successfully'
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to delete task',
      message: error.message
    });
  }
});

/**
 * @route   GET /api/tasks/stats/count
 * @desc    获取任务统计
 * @access  Public
 */
router.get('/stats/count', (req, res) => {
  try {
    const stats = TaskModel.count();
    res.json({
      success: true,
      data: stats
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: 'Failed to get task statistics',
      message: error.message
    });
  }
});

module.exports = router;

