const db = require('../db');
const { v4: uuidv4 } = require('uuid');

class TaskModel {
  /**
   * 创建新任务
   * @param {Object} taskData - { title, description, status }
   * @returns {Object} 创建的任务对象
   */
  static create(taskData) {
    const { title, description = '', status = 'pending' } = taskData;
    const id = uuidv4();
    const created_at = new Date().toISOString();
    const updated_at = created_at;

    const stmt = db.prepare(`
      INSERT INTO tasks (id, title, description, status, created_at, updated_at)
      VALUES (?, ?, ?, ?, ?, ?)
    `);
    stmt.run(id, title, description, status, created_at, updated_at);

    return this.findById(id);
  }

  /**
   * 根据 ID 查找任务
   * @param {string} id
   * @returns {Object|null}
   */
  static findById(id) {
    const stmt = db.prepare('SELECT * FROM tasks WHERE id = ?');
    return stmt.get(id) || null;
  }

  /**
   * 查找所有任务
   * @param {Object} options - { status, limit, offset }
   * @returns {Array}
   */
  static findAll(options = {}) {
    let query = 'SELECT * FROM tasks';
    const params = [];

    if (options.status) {
      query += ' WHERE status = ?';
      params.push(options.status);
    }

    query += ' ORDER BY created_at DESC';

    if (options.limit) {
      query += ' LIMIT ?';
      params.push(options.limit);
      if (options.offset) {
        query += ' OFFSET ?';
        params.push(options.offset);
      }
    }

    const stmt = db.prepare(query);
    return stmt.all(...params);
  }

  /**
   * 更新任务
   * @param {string} id
   * @param {Object} updates - { title, description, status }
   * @returns {Object|null} 更新后的任务
   */
  static update(id, updates) {
    const allowedFields = ['title', 'description', 'status'];
    const fields = [];
    const values = [];

    for (const field of allowedFields) {
      if (updates[field] !== undefined) {
        fields.push(`${field} = ?`);
        values.push(updates[field]);
      }
    }

    if (fields.length === 0) {
      return this.findById(id);
    }

    // 不手动设置 updated_at，由数据库触发器自动更新
    values.push(id);

    const sql = `UPDATE tasks SET ${fields.join(', ')} WHERE id = ?`;
    const stmt = db.prepare(sql);
    const result = stmt.run(...values);

    if (result.changes === 0) {
      return null;
    }

    return this.findById(id);
  }

  /**
   * 删除任务
   * @param {string} id
   * @returns {boolean} 是否删除成功
   */
  static delete(id) {
    const stmt = db.prepare('DELETE FROM tasks WHERE id = ?');
    const result = stmt.run(id);
    return result.changes > 0;
  }

  /**
   * 统计任务数量
   * @returns {Object} { total, pending, in_progress, completed }
   */
  static count() {
    const total = db.prepare('SELECT COUNT(*) as count FROM tasks').get().count;
    const pending = db.prepare("SELECT COUNT(*) as count FROM tasks WHERE status = 'pending'").get().count;
    const in_progress = db.prepare("SELECT COUNT(*) as count FROM tasks WHERE status = 'in_progress'").get().count;
    const completed = db.prepare("SELECT COUNT(*) as count FROM tasks WHERE status = 'completed'").get().count;

    return { total, pending, in_progress, completed };
  }
}

module.exports = TaskModel;

