const { test, expect } = require('@playwright/test');

test.describe('Todo App E2E Tests', () => {
  // 假设前端应用运行在 http://localhost:5173 (Vite 默认端口)
  // 如果端口不同，请修改 baseURL
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    // 等待应用加载
    await page.waitForLoadState('networkidle');
  });

  test('should display empty state when no tasks exist', async ({ page }) => {
    // 验证空列表提示显示
    const emptyState = page.locator('[data-testid="empty-state"]');
    await expect(emptyState).toBeVisible();
  });

  test('should create a new task', async ({ page }) => {
    const titleInput = page.locator('[data-testid="task-title-input"]');
    const descInput = page.locator('[data-testid="task-description-input"]');
    const addButton = page.locator('[data-testid="add-task-button"]');

    await titleInput.fill('Buy groceries');
    await descInput.fill('Milk, Eggs, Bread');
    await addButton.click();

    // 验证任务出现在列表中
    const taskItem = page.locator('[data-testid="task-item"]:has-text("Buy groceries")');
    await expect(taskItem).toBeVisible();
    await expect(taskItem).toContainText('Buy groceries');
    await expect(taskItem).toContainText('Milk, Eggs, Bread');
  });

  test('should create task without description', async ({ page }) => {
    const titleInput = page.locator('[data-testid="task-title-input"]');
    const addButton = page.locator('[data-testid="add-task-button"]');

    await titleInput.fill('Simple task');
    await addButton.click();

    const taskItem = page.locator('[data-testid="task-item"]:has-text("Simple task")');
    await expect(taskItem).toBeVisible();
  });

  test('should prevent adding task with empty title', async ({ page }) => {
    const addButton = page.locator('[data-testid="add-task-button"]');

    await addButton.click();

    // 验证错误提示
    const errorMessage = page.locator('[data-testid="error-message"]');
    await expect(errorMessage).toContainText('Title is required');
  });

