import React, { useState } from 'react';

const TaskInput = ({ onAddTask, disabled = false }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!title.trim() || isSubmitting || disabled) return;

    setIsSubmitting(true);
    try {
      const result = await onAddTask(title.trim(), description.trim());
      if (result?.success) {
        setTitle('');
        setDescription('');
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit(e);
    }
  };

  return (
    <form
      onSubmit={handleSubmit}
      style={{
        padding: '16px',
        borderBottom: '1px solid #E5E7EB',
        backgroundColor: '#FFFFFF'
      }}
    >
      <div
        style={{
          display: 'flex',
          gap: '8px',
          marginBottom: '8px'
        }}
      >
        <input
          type="text"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="添加新任务..."
          disabled={disabled || isSubmitting}
          aria-label="任务标题"
          required
          maxLength={200}
          style={{
            flex: 1,
            padding: '0 16px',
            height: '44px',
            border: '1px solid #E5E7EB',
            borderRadius: '12px',
            fontSize: '16px',
            color: '#111827',
            outline: 'none',
            transition: 'border-color 0.2s',
            backgroundColor: disabled ? '#F9FAFB' : '#FFFFFF'
          }}
          onFocus={(e) => {
            e.target.style.borderColor = '#3B82F6';
          }}
          onBlur={(e) => {
            e.target.style.borderColor = '#E5E7EB';
          }}
        />
        <button
          type="submit"
          disabled={!title.trim() || isSubmitting || disabled}
          aria-label="添加任务"
          style={{
            padding: '0 24px',
            height: '44px',
            backgroundColor: (!title.trim() || isSubmitting || disabled)
              ? '#9CA3AF'
              : '#3B82F6',
            color: '#FFFFFF',
            border: 'none',
            borderRadius: '12px',
            fontSize: '14px',
            fontWeight: '500',
            cursor: (!title.trim() || isSubmitting || disabled)
              ? 'not-allowed'
              : 'pointer',
            transition: 'background-color 0.2s',
            whiteSpace: 'nowrap'
          }}
          onMouseEnter={(e) => {
            if (!title.trim() || isSubmitting || disabled) return;
            e.target.style.backgroundColor = '#2563EB';
          }}
          onMouseLeave={(e) => {
            if (!title.trim() || isSubmitting || disabled) return;
            e.target.style.backgroundColor = '#3B82F6';
          }}
        >
          {isSubmitting ? '...' : '添加'}
        </button>
      </div>

      <input
        type="text"
        value={description}
        onChange={(e) => setDescription(e.target.value)}
        placeholder="添加描述（可选）"
        disabled={disabled || isSubmitting}
        aria-label="任务描述"
        maxLength={500}
        style={{
          width: '100%',
          padding: '0 16px',
          height: '36px',
          border: '1px solid #E5E7EB',
          borderRadius: '8px',
          fontSize: '14px',
          color: '#111827',
          outline: 'none',
          transition: 'border-color 0.2s',
          backgroundColor: disabled ? '#F9FAFB' : '#FFFFFF',
          marginTop: '8px'
        }}
        onFocus={(e) => {
          e.target.style.borderColor = '#3B82F6';
        }}
        onBlur={(e) => {
          e.target.style.borderColor = '#E5E7EB';
        }}
      />
    </form>
  );
};

export default TaskInput;

import React, { useState } from 'react';
