const STATUS_FILTERS = {
  ALL: 'all',
  PENDING: 'pending',
  COMPLETED: 'completed'
};

const FilterBar = ({ filter, onFilterChange }) => {
  const filters = [
    { key: STATUS_FILTERS.ALL, label: '全部' },
    { key: STATUS_FILTERS.PENDING, label: '待完成' },
    { key: STATUS_FILTERS.COMPLETED, label: '已完成' }
  ];

  return (
    <div
      role="tablist"
      aria-label="任务过滤器"
      style={{
        display: 'flex',
        gap: '8px',
        borderBottom: '1px solid #E5E7EB',
        padding: '0 16px',
        marginBottom: '16px'
      }}
    >
      {filters.map(({ key, label }) => (
        <button
          key={key}
          role="tab"
          aria-selected={filter === key}
          onClick={() => onFilterChange(key)}
          style={{
            flex: 1,
            background: 'transparent',
            border: 'none',
            borderBottom: filter === key ? '2px solid #3B82F6' : '2px solid transparent',
            padding: '12px 8px',
            fontSize: '15px',
            fontWeight: '500',
            color: filter === key ? '#3B82F6' : '#6B7280',
            cursor: 'pointer',
            transition: 'all 0.2s ease',
            outline: 'none',
            marginBottom: '-1px'
          }}
          onMouseEnter={(e) => {
            if (filter !== key) {
              e.target.style.color = '#3B82F6';
            }
          }}
          onMouseLeave={(e) => {
            if (filter !== key) {
              e.target.style.color = '#6B7280';
            }
          }}
        >
          {label}
        </button>
      ))}
    </div>
  );
};

